mapper.insert:
 
		/* com.study.board.mapper.BoardMapper.contentWrite */
			INSERT INTO BOARD
				(
				  BOARD_ID
				, TITLE
				, TEXT
				, BOARD_DATE
				, MEMBER_ID
				)
			VALUES
				(
				  (SELECT NVL(MAX(BOARD_ID)+1, 0) FROM BOARD)
				, #{title}
				, #{text}
				, SYSDATE
				, #{memberId}
				)
